function rectangleArea(rectangles) {
    const mod = 1e9 + 7;
    let n = rectangles.length;
    let X = new Set(), Y = new Set();
    for (const rect of rectangles) {
        X.add(rect[0]);
        X.add(rect[2]);
        Y.add(rect[1]);
        Y.add(rect[3]);
    }
    let sortedX = Array.from(X).sort((a, b) => a - b);
    let sortedY = Array.from(Y).sort((a, b) => a - b);

    let cnt = Array.from({ length: X.size - 1 }, () => Array.from({ length: Y.size - 1 }, () => 0));

    for (const rect of rectangles) {
        let x1_idx = sortedX.indexOf(rect[0]);
        let x2_idx = sortedX.indexOf(rect[2]) - 1;
        let y1_idx = sortedY.indexOf(rect[1]);
        let y2_idx = sortedY.indexOf(rect[3]) - 1;
        for (let i = x1_idx; i <= x2_idx; i++) {
            for (let j = y1_idx; j <= y2_idx; j++) {
                cnt[i][j] = 1;
            }
        }
    }

    let total_area = 0;
    for (let i = 0; i < X.size - 1; i++) {
        for (let j = 0; j < Y.size - 1; j++) {
            if (cnt[i][j]) {
                total_area += (sortedX[i + 1] - sortedX[i]) * (sortedY[j + 1] - sortedY[j]);
                total_area %= mod;
            }
        }
    }

    return total_area;
}
```

    - For each rectangle, add its x-coordinates and y-coordinates (both left and right) into two separate sets X and Y.
- Convert the sets X and Y to sorted lists (sortedX, sortedY).
- Create an 2D array (matrix) cnt, which will represent the overlap of rectangles, i.e., cnt[i][j] == 1 if any rectangle covers that area.
- Iterate through the rectangles and for each rectangle, find its left and right, top and bottom boundaries in the sortedX and sortedY lists.
- Mark cnt[i][j] = 1 for each rectangle covering the area between indices i and j.
- Initialize a variable total_area to 0. Iterate over the cnt matrix, and for each cell with value 1, increment total_area by the area of the cell (product of the difference in x and y-coordinates).
- Return total_area modulo 10^9 + 7.

